function applyQueries(n, queries) {
    const mat = new Array(n).fill(0).map(() => new Array(n).fill(0));

    for (const query of queries) {
        for (let i = query[0]; i <= query[2]; i++) {
            for (let j = query[1]; j <= query[3]; j++) {
                mat[i][j]++;
            }
        }
    }

    return mat;
}
